import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './UserPages.module.css';

const statusBadge = (status) => {
  const map = { confirmed: styles.badgeGreen, pending: styles.badgeYellow, cancelled: styles.badgeRed };
  return map[status] || '';
};

const BookingsPage = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [error, setError]       = useState('');

  const load = () => {
    setLoading(true);
    api.get('/bookings')
      .then((res) => setBookings(res.data?.data || []))
      .catch(() => setError('Failed to load bookings.'))
      .finally(() => setLoading(false));
  };

  useEffect(load, []);

  const cancel = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;
    try {
      await api.put(`/bookings/${id}`, { status: 'cancelled' });
      load();
    } catch {
      alert('Could not cancel booking.');
    }
  };

  return (
    <>
      <Navbar />
      <div className={styles.page}>
        <h1>📅 My Bookings</h1>
        {loading && <p>Loading…</p>}
        {error   && <p style={{ color: 'red' }}>{error}</p>}
        {!loading && !error && (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Package</th>
                <th>Date</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {bookings.length === 0 ? (
                <tr><td colSpan={4}>No bookings yet.</td></tr>
              ) : bookings.map((b) => (
                <tr key={b._id}>
                  <td>{b.package?.name || '—'}</td>
                  <td>{new Date(b.createdAt).toLocaleDateString()}</td>
                  <td>
                    <span className={`${styles.badge} ${statusBadge(b.status)}`}>
                      {b.status}
                    </span>
                  </td>
                  <td>
                    {b.status !== 'cancelled' && (
                      <button
                        className={`${styles.btnSm} ${styles.btnDanger}`}
                        onClick={() => cancel(b._id)}
                      >
                        Cancel
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </>
  );
};

export default BookingsPage;
